function isEmpty(t){for(let e in t)return!1;return!0}let currentCaptcha="",isTextCaptcha=!0,captchaLength=0;function generateTextCaptcha(){let t="AaBbCcDdEeFfGg123",e="";for(let n=0;n<6;n++)e+=t.charAt(Math.floor(Math.random()*t.length));return captchaLength=6,e}function generateMathCaptcha(){let t=Math.floor(10*Math.random())+1,e=Math.floor(10*Math.random())+1;return captchaLength=(t+e).toString().length,{text:t+" + "+e+" = ?",answer:t+e}}function createCaptcha(){isTextCaptcha?(currentCaptcha=generateTextCaptcha(),document.getElementById("captchaText").textContent="Введите текст: "+currentCaptcha):(currentCaptcha=generateMathCaptcha(),document.getElementById("captchaText").textContent="Решите пример: "+currentCaptcha.text)}function checkInput(){let t=document.getElementById("userInput").value,e=document.getElementById("message"),n=document.getElementById("submitBtn");if(isEmpty({input:t})){n.disabled=!0,e.textContent="";return}if(t.length===captchaLength)(isTextCaptcha?t===currentCaptcha:parseInt(t)===currentCaptcha.answer)?(e.textContent="Верно! Форма разблокирована.",e.className="success",n.disabled=!1):(e.textContent="Неверно!",e.className="error",n.disabled=!0,isTextCaptcha&&(isTextCaptcha=!1,createCaptcha(),document.getElementById("userInput").value="",e.textContent="Попробуйте решить пример"));else e.textContent="",n.disabled=!0}createCaptcha(),document.getElementById("userInput").addEventListener("input",checkInput),document.getElementById("submitBtn").onclick=function(){alert("Форма отправлена!"),document.getElementById("submitBtn").disabled=!0,document.getElementById("userInput").value="",document.getElementById("message").textContent="",isTextCaptcha=!0,createCaptcha()};